```class SeatManager {

    private int n;
    private int[] seats;
    private int available;

    public SeatManager(int n) {
        this.n = n;
        seats = new int[n];
        Arrays.fill(seats, -1);
        available = 1;
    }

    public int reserve() {
        return seats[available++] - 1;
    }

    public void unreserve(int seatNumber) {
        seats[seatNumber - 1] = available++;
    }
}
